/// <summary>
/// This class contain the logic for Lookup for Journalname field
/// </summary>
internal final class ETGJournalNameLookupEvent
{

}

Method.Source:
/// <summary>
/// Contain the lookup logic
/// </summary>
/// <param name="sender">FormControl</param>
/// <param name="e">FormControlEventArgs</param>
[FormControlEventHandler(formControlStr(InventParameters, InventParameters_ETGJournalName), FormControlEventType::Lookup)]
public static void InventParameters_ETGJournalName_OnLookup(FormControl sender, FormControlEventArgs e)
{
    Query                   query = new Query();
    QueryBuildRange         qbr;
    QueryBuildDataSource    queryBuildDataSource  = query.addDataSource(tableNum(InventJournalName));
    SysTableLookup          tableLookup = SysTableLookup::newParameters(tablenum(InventJournalName), sender);
    tableLookup.addLookupfield(fieldnum(InventJournalName, JournalNameId));
    tableLookup.addLookupfield(fieldnum(InventJournalName, Description));
    qbr = queryBuildDataSource.addRange(fieldNum(InventJournalName, ETGManualAdditionorDeletion));
    qbr.value(SysQuery::value(0));
    tableLookup.parmQuery(query);
    tableLookup.performFormLookup();

    //cancel the call to super() to prevent the system from trying to show
    FormControlCancelableSuperEventArgs cancelableSuperEventArgs = e as FormControlCancelableSuperEventArgs;

    cancelableSuperEventArgs.CancelSuperCall();

}
